# ============================================================
# Encryption utilities for sensitive data at rest
# ============================================================
class DataProtector:
    """Handles encryption/hashing of sensitive data before storing in Redis."""

    def __init__(self, encryption_key: str):
        if not encryption_key:
            raise ValueError("ENCRYPTION_KEY environment variable must be set for data protection")
        self._key = encryption_key.encode('utf-8')

    def hmac_hash(self, data: str) -> str:
        """Create HMAC hash for data that needs to be looked up by value (e.g., token lookup)."""
        return hmac.new(self._key, data.encode('utf-8'), hashlib.sha256).hexdigest()

    def mask_for_logging(self, value: str, visible_chars: int = 4) -> str:
        """Mask sensitive data for safe logging."""
        if len(value) <= visible_chars:
            return "****"
        return value[:visible_chars] + "****" + value[-visible_chars:]


