class DistributedCacheService:
    """
    Service for managing distributed caching of sensitive user data.
    Implements proper TTL, namespacing, and data protection.
    """

    # Key namespace prefixes
    NS_SESSION = "session:"
    NS_API_KEY = "apikey:"
    NS_REFRESH_TOKEN = "refresh:"
    NS_USER_CACHE = "usercache:"
    NS_RATE_LIMIT = "ratelimit:"
    NS_TOKEN_LOOKUP = "tokenlookup:"

    def __init__(self, redis_manager: RedisClusterManager, config: Config, protector: DataProtector):
        self._redis = redis_manager
        self._config = config
        self._protector = protector

    def _serialize(self, data: Dict[str, Any]) -> str:
        """Serialize data to JSON string."""
        return json.dumps(data, default=str)

    def _deserialize(self, data: str) -> Dict[str, Any]:
        """Deserialize JSON string to dict."""
        if data is None:
            return None
        return json.loads(data)

    # ---- Session Token Management ----

    def create_session(self, user_id: str, metadata: Optional[Dict] = None) -> Dict[str, str]:
        """
        Create a new session token for a user.
        Returns the session token and session ID.
        """
        session_id = secrets.token_urlsafe(32)
        session_token = secrets.token_urlsafe(64)
        
        # Hash the token for storage - never store raw tokens
        token_hash = self._protector.hmac_hash(session_token)

        session_data = {
            "user_id": user_id,
            "session_id": session_id,
            "token_hash": token_hash,
            "created_at": datetime.utcnow().isoformat(),
            "metadata": metadata or {},
        }

        # Store session data keyed by session_id
        session_key = f"{self.NS_SESSION}{session_id}"
        # Store a reverse lookup: token_hash -> session_id
        lookup_key = f"{self.NS_TOKEN_LOOKUP}{token_hash}"

        pipe = self._redis.client.pipeline()
        pipe.setex(session_key, self._config.SESSION_TOKEN_TTL, self._serialize(session_data))
        pipe.setex(lookup_key, self._config.SESSION_TOKEN_TTL, session_id)
        pipe.execute()

        logger.info(
            f"Session created for user {self._protector.mask_for_logging(user_id)} "
            f"with session_id {self._protector.mask_for_logging(session_id)}"
        )

        return {
            "session_id": session_id,
            "session_token": session_token,
            "expires_in": self._config.SESSION_TOKEN_TTL,
        }

    def validate_session(self, session_token: str) -> Optional[Dict[str, Any]]:
        """Validate a session token and return session data if valid."""
        token_hash = self._protector.hmac_hash(session_token)
        lookup_key = f"{self.NS_TOKEN_LOOKUP}{token_hash}"

        session_id = self._redis.client.get(lookup_key)
        if not session_id:
            logger.warning("Session validation failed: token not found")
            return None

        session_key = f"{self.NS_SESSION}{session_id}"
        session_data_raw = self._redis.client.get(session_key)
        if not session_data_raw:
            logger.warning("Session validation failed: session data expired")
            # Clean up orphaned lookup key
            self._redis.client.delete(lookup_key)
            return None

        session_data = self._deserialize(session_data_raw)

        # Verify token hash matches
        if session_data.get("token_hash") != token_hash:
            logger.warning("Session validation failed: token hash mismatch")
            return None

        logger.info(f"Session validated for user {self._protector.mask_for_logging(session_data['user_id'])}")
        
        # Return safe subset (exclude token_hash)
        return {
            "user_id": session_data["user_id"],
            "session_id": session_data["session_id"],
            "created_at": session_data["created_at"],
            "metadata": session_data.get("metadata", {}),
        }

    def revoke_session(self, session_id: str) -> bool:
        """Revoke a session by session ID."""
        session_key = f"{self.NS_SESSION}{session_id}"
        session_data_raw = self._redis.client.get(session_key)

        if session_data_raw:
            session_data = self._deserialize(session_data_raw)
            token_hash = session_data.get("token_hash")
            if token_hash:
                lookup_key = f"{self.NS_TOKEN_LOOKUP}{token_hash}"
                self._redis.client.delete(lookup_key)

        deleted = self._redis.client.delete(session_key)
        logger.info(f"Session {self._protector.mask_for_logging(session_id)} revoked: {bool(deleted)}")
        return bool(deleted)

    def revoke_all_user_sessions(self, user_id: str) -> int:
        """
        Revoke all sessions for a user.
        Note: This requires scanning, which should be used judiciously.
        """
        count = 0
        cursor = 0
        pattern = f"{self.NS_SESSION}*"

        while True:
            cursor, keys = self._redis.client.scan(cursor=cursor, match=pattern, count=100)
            for key in keys:
                session_data_raw = self._redis.client.get(key)
                if session_data_raw:
                    session_data = self._deserialize(session_data_raw)
                    if session_data.get("user_id") == user_id:
                        session_id = session_data.get("session_id")
                        if session_id:
                            self.revoke_session(session_id)
                            count += 1
            if cursor == 0:
                break

        logger.info(f"Revoked {count} sessions for user {self._protector.mask_for_logging(user_id)}")
        return count

    # ---- API Key Management ----

    def store_api_key(self, user_id: str, key_name: str, permissions: list = None) -> Dict[str, str]:
        """
        Generate and store a new API key for a user.
        Returns the API key (only shown once).
        """
        api_key = f"sk_{secrets.token_urlsafe(48)}"
        key_hash = self._protector.hmac_hash(api_key)
        key_id = secrets.token_urlsafe(16)

        key_data = {
            "key_id": key_id,
            "user_id": user_id,
            "key_name": key_name,
            "key_hash": key_hash,
            "key_prefix": api_key[:7],  # Store prefix for identification
            "permissions": permissions or ["read"],
            "created_at": datetime.utcnow().isoformat(),
            "last_used_at": None,
        }

        # Store API key data keyed by key_id
        apikey_key = f"{self.NS_API_KEY}{key_id}"
        # Reverse lookup by hash
        lookup_key = f"{self.NS_TOKEN_LOOKUP}apikey:{key_hash}"

        pipe = self._redis.client.pipeline()
        pipe.setex(apikey_key, self._config.API_KEY_TTL, self._serialize(key_data))
        pipe.setex(lookup_key, self._config.API_KEY_TTL, key_id)
        pipe.execute()

        logger.info(
            f"API key '{key_name}' created for user {self._protector.mask_for_logging(user_id)} "
            f"with key_id {key_id}"
        )

        return {
            "key_id": key_id,
            "api_key": api_key,
            "key_name": key_name,
            "expires_in": self._config.API_KEY_TTL,
        }

    def validate_api_key(self, api_key: str) -> Optional[Dict[str, Any]]:
        """Validate an API key and return associated data if valid."""
        key_hash = self._protector.hmac_hash(api_key)
        lookup_key = f"{self.NS_TOKEN_LOOKUP}apikey:{key_hash}"

        key_id = self._redis.client.get(lookup_key)
        if not key_id:
            logger.warning(f"API key validation failed: key not found (prefix: {api_key[:7]}...)")
            return None

        apikey_key = f"{self.NS_API_KEY}{key_id}"
        key_data_raw = self._redis.client.get(apikey_key)
        if not key_data_raw:
            logger.warning("API key validation failed: key data expired")
            self._redis.client.delete(lookup_key)
            return None

        key_data = self._deserialize(key_data_raw)

        if key_data.get("key_hash") != key_hash:
            logger.warning("API key validation failed: hash mismatch")
            return None

        # Update last_used_at
        key_data["last_used_at"] = datetime.utcnow().isoformat()
        self._redis.client.setex(
            apikey_key,
            self._redis.client.ttl(apikey_key),
            self._serialize(key_data)
        )

        return {
            "key_id": key_data["key_id"],
            "user_id": key_data["user_id"],
            "key_name": key_data["key_name"],
            "permissions": key_data["permissions"],
        }

    def revoke_api_key(self, key_id: str) -> bool:
        """Revoke an API key by key ID."""
        apikey_key = f"{self.NS_API_KEY}{key_id}"
        key_data_raw = self._redis.client.get(apikey_key)

        if key_data_raw:
            key_data = self._deserialize(key_data_raw)
            key_hash = key_data.get("key_hash")
            if key_hash:
                lookup_key = f"{self.NS_TOKEN_LOOKUP}apikey:{key_hash}"
                self._redis.client.delete(lookup_key)

        deleted = self._redis.client.delete(apikey_key)
        logger.info(f"API key {key_id} revoked: {bool(deleted)}")
        return bool(deleted)

    # ---- Refresh Token Management ----

    def store_refresh_token(self, user_id: str, session_id: str) -> Dict[str, str]:
        """Create and store a refresh token associated with a session."""
        refresh_token = secrets.token_urlsafe(64)
        token_hash = self._protector.hmac_hash(refresh_token)
        token_id = secrets.token_urlsafe(16)

        token_data = {
            "token_id": token_id,
            "user_id": user_id,
            "session_id": session_id,
            "token_hash": token_hash,
            "created_at": datetime.utcnow().isoformat(),
            "used": False,
        }

        token_key = f"{self.NS_REFRESH_TOKEN}{token_id}"
        lookup_key = f"{self.NS_TOKEN_LOOKUP}refresh:{token_hash}"

        pipe = self._redis.client.pipeline()
        pipe.setex(token_key, self._config.REFRESH_TOKEN_TTL, self._serialize(token_data))
        pipe.setex(lookup_key, self._config.REFRESH_TOKEN_TTL, token_id)
        pipe.execute()

        logger.info(f"Refresh token created for session {self._protector.mask_for_logging(session_id)}")

        return {
            "token_id": token_id,
            "refresh_token": refresh_token,
            "expires_in": self._config.REFRESH_TOKEN_TTL,
        }

    def use_refresh_token(self, refresh_token: str) -> Optional[Dict[str, Any]]:
        """
        Validate and consume a refresh token (one-time use).
        Returns user/session info if valid.
        """
        token_hash = self._protector.hmac_hash(refresh_token)
        lookup_key = f"{self.NS_TOKEN_LOOKUP}refresh:{token_hash}"

        token_id = self._redis.client.get(lookup_key)
        if not token_id:
            logger.warning("Refresh token validation failed: token not found")
            return None

        token_key = f"{self.NS_REFRESH_TOKEN}{token_id}"
        token_data_raw = self._redis.client.get(token_key)
        if not token_data_raw:
            self._redis.client.delete(lookup_key)
            return None

        token_data = self._deserialize(token_data_raw)

        if token_data.get("token_hash") != token_hash:
            logger.warning("Refresh token validation failed: hash mismatch")
            return None

        # One-time use: delete after use to prevent replay
        if token_data.get("used"):
            logger.warning("Refresh token replay detected! Revoking all related sessions.")
            self.revoke_session(token_data["session_id"])
            self._redis.client.delete(token_key)
            self._redis.client.delete(lookup_key)
            return None

        # Mark as used and delete
        pipe = self._redis.client.pipeline()
        pipe.delete(token_key)
        pipe.delete(lookup_key)
        pipe.execute()

        logger.info(f"Refresh token consumed for user {self._protector.mask_for_logging(token_data['user_id'])}")

        return {
            "user_id": token_data["user_id"],
            "session_id": token_data["session_id"],
        }

    # ---- User Data Cache ----

    def cache_user_data(self, user_id: str, data: Dict[str, Any]) -> bool:
        """Cache non-sensitive user profile data with appropriate TTL."""
        # Strip any sensitive fields before caching
        safe_data = {k: v for k, v in data.items() 
                     if k not in ("password", "password_hash", "ssn", "credit_card", "secret")}
        
        cache_key = f"{self.NS_USER_CACHE}{user_id}"
        self._redis.client.setex(cache_key, self._config.USER_CACHE_TTL, self._serialize(safe_data))
        logger.debug(f"Cached user data for {self._protector.mask_for_logging(user_id)}")
        return True

    def get_cached_user_data(self, user_id: str) -> Optional[Dict[str, Any]]:
        """Retrieve cached user data."""
        cache_key = f"{self.NS_USER_CACHE}{user_id}"
        data = self._redis.client.get(cache_key)
        if data:
            logger.debug(f"Cache hit for user {self._protector.mask_for_logging(user_id)}")
            return self._deserialize(data)
        logger.debug(f"Cache miss for user {self._protector.mask_for_logging(user_id)}")
        return None

    def invalidate_user_cache(self, user_id: str) -> bool:
        """Invalidate cached user data."""
        cache_key = f"{self.NS_USER_CACHE}{user_id}"
        deleted = self._redis.client.delete(cache_key)
        return bool(deleted)

    # ---- Rate Limiting ----

    def check_rate_limit(self, identifier: str, max_requests: int = None) -> Dict[str, Any]:
        """
        Implement sliding window rate limiting.
        Returns rate limit status.
        """
        max_req = max_requests or self._config.RATE_LIMIT_MAX_REQUESTS
        rate_key = f"{self.NS_RATE_LIMIT}{identifier}"
        
        pipe = self._redis.client.pipeline()
        pipe.incr(rate_key)
        pipe.ttl(rate_key)
        results = pipe.execute()

        current_count = results[0]
        ttl = results[1]

        # Set TTL on first request
        if ttl == -1:
            self._redis.client.expire(rate_key, self._config.RATE_LIMIT_TTL)
            ttl = self._config.RATE_LIMIT_TTL

        allowed = current_count <= max_req

        if not allowed:
            logger.warning(f"Rate limit exceeded for {self._protector.mask_for_logging(identifier)}")

        return {
            "allowed": allowed,
            "current": current_count,
            "limit": max_req,
            "remaining": max(0, max_req - current_count),
            "reset_in": ttl,
        }


