# ---- Refresh Token Endpoints ----

@app.route("/refresh-tokens", methods=["POST"])
@require_service_auth
@rate_limit(max_requests=50)
def create_refresh_token():
    """Create a refresh token for a session."""
    data = request.get_json()
    if not data or "user_id" not in data or "session_id" not in data:
        return jsonify({"error": "user_id and session_id are required"}), 400

    try:
        result = get_cache_service().store_refresh_token(
            user_id=data["user_id"],
            session_id=data["session_id"]
        )
        return jsonify(result), 201
    except RedisError as e:
        logger.error(f"Redis error creating refresh token: {e}")
        return jsonify({"error": "Service temporarily unavailable"}), 503


@app.route("/refresh-tokens/use", methods=["POST"])
@require_service_auth
@rate_limit(max_requests=20)
def use_refresh_token():
    """Use a refresh token (one-time use)."""
    data = request.get_json()
    if not data or "refresh_token" not in data:
        return jsonify({"error": "refresh_token is required"}), 400

    try:
        result = get_cache_service().use_refresh_token(data["refresh_token"])
        if result:
            # Create new session and refresh token
            new_session = get_cache_service().create_session(
                user_id=result["user_id"],
                metadata={"refreshed_from_session": result["session_id"]}
            )
            new_refresh = get_cache_service().store_refresh_token(
                user_id=result["user_id"],
                session_id=new_session["session_id"]
            )
            return jsonify({
                "session": new_session,
                "refresh_token": new_refresh,
            }), 200
        return jsonify({"valid": False, "error": "Invalid or expired refresh token"}), 401
    except RedisError as e:
        logger.error(f"Redis error using refresh token: {e}")
        return jsonify({"error": "Service temporarily unavailable"}), 503


